type Item = {
  type: string;
  material: string;
  enchantment: number;
  cursed: boolean;
};

type QuoteStep = { op: "quote"; items: Item[] };
type Step = QuoteStep | { op: string };

type Scenario = {
  customer: { yearsWithMHPCO: number };
  steps: Step[];
};

const PROCESSING_FEE = 5;

const basePremium = (type: string): number => {
  if (type === "sword") return 100;
  return 0;
};

const applyPercent = (value: number, percent: number): number => {
  return Math.ceil((value * (100 + percent)) / 100);
};

const quotePremium = (step: QuoteStep): number => {
  const itemTotal = step.items.reduce((sum, item) => {
    let p = basePremium(item.type);
    if (item.cursed) p = applyPercent(p, 50);
    return sum + p;
  }, 0);
  const withFirstContract = applyPercent(itemTotal, 10);
  return withFirstContract + PROCESSING_FEE;
};

export const runScenario = (input: unknown): { results: unknown[] } => {
  const scenario = input as Scenario;
  const results = scenario.steps.map((step) => {
    return { premium: quotePremium(step as QuoteStep) };
  });
  return { results };
};

