        items: quote.items,
        insuranceSum: sum,
        remainingCap: 2 * sum,
      });
      return { premium };
    }
    const claim = step as ClaimStep;
    const policy = policies.get(claim.policy)!;
    return processClaim(policy, claim.incident.damages);
  });
