type Item = {
  type: string;
  material: string;
  enchantment: number;
  cursed: boolean;
};

type Damage = { itemType: string; amount: number };
type QuoteStep = { op: "quote"; items: Item[] };
type ClaimStep = {
  op: "claim";
  policy: number;
  incident: { cause: string; damages: Damage[] };
};
type Step = QuoteStep | ClaimStep;

type Scenario = {
  customer: { yearsWithMHPCO: number };
  steps: Step[];
};

const ITEM_BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
};

const ITEM_INSURANCE_VALUE: Record<string, number> = {
  sword: 1000,
  amulet: 600,
  staff: 800,
  potion: 400,
  rune: 250,
};

const COMPONENT_BLOCK_DISCOUNT = 15; // 3×25 = 75 → 60
const COMPONENT_TYPES = new Set(["rune"]);
const PROCESSING_FEE = 5;
const DEDUCTIBLE = 100;

const basePremium = (type: string): number => ITEM_BASE_PREMIUM[type] ?? 0;
const insuranceValue = (type: string): number => ITEM_INSURANCE_VALUE[type] ?? 0;

const applyPercent = (value: number, percent: number): number => {
  return Math.ceil((value * (100 + percent)) / 100);
};

const componentBlockDiscount = (items: Item[]): number => {
  const counts = new Map<string, number>();
  for (const item of items) {
    if (COMPONENT_TYPES.has(item.type)) {
      counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
    }
  }
  let discount = 0;
  for (const count of counts.values()) {
    discount += Math.floor(count / 3) * COMPONENT_BLOCK_DISCOUNT;
  }
  return discount;
};

const quotePremium = (
  step: QuoteStep,
  customer: Scenario["customer"],
  priorContracts: number,
): number => {
  const itemTotal = step.items.reduce((sum, item) => {
    let p = basePremium(item.type);
    if (item.cursed) p = applyPercent(p, 50);
    if (item.enchantment >= 5) p = applyPercent(p, 30);
    return sum + p;
  }, 0);
  let total = itemTotal - componentBlockDiscount(step.items);
  if (customer.yearsWithMHPCO >= 2) total = applyPercent(total, -20);
  const isFirstContract = priorContracts === 0;
  total = applyPercent(total, isFirstContract ? 10 : -15);
  return total + PROCESSING_FEE;
};

const insuranceSum = (items: Item[]): number =>
  items.reduce((sum, item) => sum + insuranceValue(item.type), 0);

type Policy = { items: Item[]; insuranceSum: number; remainingCap: number };

const reimbursementForDamage = (policy: Policy, damage: Damage): number => {
  const item = policy.items.find((it) => it.type === damage.itemType);
  if (item && item.material === "dragon") return damage.amount;
  return 0;
};

const processClaim = (
  policy: Policy,
  damages: Damage[],
): { payout: number; remainingCap: number } => {
  const gross = damages.reduce(
    (sum, d) => sum + reimbursementForDamage(policy, d),
    0,
  );
  const afterDeductible = Math.max(0, gross - DEDUCTIBLE);
  const payout = Math.min(afterDeductible, policy.remainingCap);
  policy.remainingCap -= payout;
  return { payout, remainingCap: policy.remainingCap };
};

export const runScenario = (input: unknown): { results: unknown[] } => {
  const scenario = input as Scenario;
  let priorContracts = 0;
  const policies = new Map<number, Policy>();
  const results: unknown[] = scenario.steps.map((step, index) => {
    if (step.op === "quote") {
      const quote = step as QuoteStep;
      const premium = quotePremium(quote, scenario.customer, priorContracts);
      priorContracts += 1;
      const sum = insuranceSum(quote.items);
      policies.set(index, {
        items: quote.items,
        insuranceSum: sum,
        remainingCap: 2 * sum,
      });
      return { premium };
    }
    const claim = step as ClaimStep;
    const policy = policies.get(claim.policy)!;
    return processClaim(policy, claim.incident.damages);
  });
  return { results };
};

import { describe, it, expect } from "vitest";
import { runScenario } from "./scenario.js";

describe("MHPCO scenario runner", () => {
  it("returns no results for an empty steps list", () => {
    const output = runScenario({ customer: { yearsWithMHPCO: 0 }, steps: [] });
    expect(output).toEqual({ results: [] });
  });
  it("quotes a single plain sword for a brand-new customer", () => {
    // Sword base 100G; new customer (0 years, first contract):
    //   100 × 1.10 (first-contract surcharge) = 110, + 5G processing fee = 115G.
    const output = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "sword", material: "steel", enchantment: 3, cursed: false },
          ],
        },
      ],
    });
    expect(output).toEqual({ results: [{ premium: 115 }] });
  });
  it("applies the 50% cursed surcharge to a quote", () => {
    // Cursed sword: 100 × 1.5 (cursed) × 1.10 (first contract) = 165, + 5G fee = 170G.
    const output = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "sword", material: "steel", enchantment: 3, cursed: true },
          ],
        },
      ],
    });
    expect(output).toEqual({ results: [{ premium: 170 }] });
  });
  it("applies the 30% high-enchantment surcharge (level >= 5)", () => {
    // Sword ench 5: 100 × 1.30 × 1.10 = 143, + 5G fee = 148G.
    const output = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "sword", material: "steel", enchantment: 5, cursed: false },
          ],
        },
      ],
    });
    expect(output).toEqual({ results: [{ premium: 148 }] });
  });
  it("applies the 20% loyalty discount for long-standing customers (>= 2 years)", () => {
    // Sword, 5-year customer, first contract:
    //   100 × 0.80 (loyalty) = 80, × 1.10 (first contract) = 88, + 5G fee = 93G.
    const output = runScenario({
      customer: { yearsWithMHPCO: 5 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "sword", material: "steel", enchantment: 3, cursed: false },
          ],
        },
      ],
    });
    expect(output).toEqual({ results: [{ premium: 93 }] });
  });
  it("applies the 15% returning-contract discount instead of the first-contract surcharge on later quotes", () => {
    // Two sword quotes for a new (0y) customer:
    //   #1 (first contract): 100 × 1.10 + 5 = 115G.
    //   #2 (returning):      100 × 0.85 + 5 = 90G.
    const sword = {
      type: "sword",
      material: "steel",
      enchantment: 3,
      cursed: false,
    };
    const output = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote", items: [sword] },
        { op: "quote", items: [sword] },
      ],
    });
    expect(output).toEqual({
      results: [{ premium: 115 }, { premium: 90 }],
    });
  });
  it("sums per-item premiums when quoting multiple items", () => {
    // Sword 100 + amulet 60 + staff 80 + potion 40 = 280; × 1.10 = 308, + 5 = 313G.
    const output = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "sword", material: "steel", enchantment: 0, cursed: false },
            { type: "amulet", material: "silver", enchantment: 0, cursed: false },
            { type: "staff", material: "oak", enchantment: 0, cursed: false },
            { type: "potion", material: "glass", enchantment: 0, cursed: false },
          ],
        },
      ],
    });
    expect(output).toEqual({ results: [{ premium: 313 }] });
  });
  it("offers the 60G block premium for three alike components", () => {
    // Three alike components form a block at 60G base premium (vs. 3×25=75G):
    //   60 × 1.10 + 5 = 71G.
    const rune = {
      type: "rune",
      material: "stone",
      enchantment: 0,
      cursed: false,
    };
    const output = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote", items: [rune, rune, rune] },
      ],
    });
    expect(output).toEqual({ results: [{ premium: 71 }] });
  });
  it("pays 0 on a claim against an ordinary item (no reimbursement rule applies)", () => {
    // Ordinary amulet (silver, ench 2): no reimbursement rule triggers → payout 0,
    // cap unchanged at 2×600 = 1200G.
    const output = runScenario({
      customer: { yearsWithMHPCO: 5 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "amulet", material: "silver", enchantment: 2, cursed: false },
          ],
        },
        {
          op: "claim",
          policy: 0,
          incident: {
            cause: "fire",
            damages: [{ itemType: "amulet", amount: 200 }],
          },
        },
      ],
    });
    expect(output).toEqual({
      results: [
        { premium: 58 },
        { payout: 0, remainingCap: 1200 },
      ],
    });
  });
  it("fully reimburses damage to a dragon-material item, minus the 100G deductible", () => {
    // Dragon sword (insurance 1000, cap 2000); damage 500G fully reimbursed:
    //   payout = 500 - 100 = 400, remainingCap = 2000 - 400 = 1600.
    const output = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "sword", material: "dragon", enchantment: 0, cursed: false },
          ],
        },
        {
          op: "claim",
          policy: 0,
          incident: {
            cause: "battle",
            damages: [{ itemType: "sword", amount: 500 }],
          },
        },
      ],
    });
    expect(output).toEqual({
      results: [
        { premium: 115 },
        { payout: 400, remainingCap: 1600 },
      ],
    });
  });
  it.todo("reimburses 50% of damage to a highly enchanted item (level >= 8), minus the 100G deductible");
  it.todo("caps total payouts at twice the insurance sum across successive claims");
});

describe("claim-office CLI", () => {
  it.todo("reads a scenario JSON from stdin and writes the results JSON to stdout");
});

